import os
import sys
from unittest.mock import patch
from io import StringIO
from mini_ai.markov import MarkovChain

MARKOV_MODEL = 'model.json'
CLI_COMMANDS = {
    'train': {'args': ['--input', '--model-out'], 'func': main.train_model},
    'generate': {'args': ['--model', '--length'], 'func': main.generate_text}
}

@patch.dict(os.environ, {'MARKOV_MODEL': MARKOV_MODEL})
def main():
    if sys.argv[1] == 'train':
        CLI_COMMANDS['train']['func']()
    elif sys.argv[1] == 'generate':
        CLI_COMMANDS['generate']['func']()

if __name__ == '__main__':
    main()

import json
from collections import defaultdict

MARKOV_MODEL = None

class MarkovChain:
    def __init__(self, order=1):
        self.order = order
        self.model = defaultdict(lambda: defaultdict(int))

    @staticmethod
    def train(text, model=None):
        global MARKOV_MODEL
        if not model:
            model = MARKOV_MODEL
        for i in range(len(text) - 1):
            key = tuple(text[i:i+model.order])
            value = text[i+model.order]
            model[key] += value
        return model

    @staticmethod
    def generate_text(model, length=5):
        if not MARKOV_MODEL:
            raise ValueError('Model not found')
        output = []
        for _ in range(length):
            key = tuple(output[-model.order:])
            value = max(model[key], key=model[key].get)
            output.append(value)
        return ''.join(output)
